import React, { useState, useEffect, useRef } from 'react';

interface Message {
  id: string;
  userId: string;
  userName: string;
  text: string;
  timestamp: number;
}

interface ChatWidgetProps {
  roomId: string;
  currentUserId: string;
  wsUrl: string;
}

interface MessageListProps {
  messages: Message[];
  onDelete: (id: string) => void;
}

const MessageList = React.memo(function MessageList({ messages, onDelete }: MessageListProps) {
  return (
    <div className="message-list">
      {messages.map(msg => (
        <div key={msg.id} className="message">
          <strong>{msg.userName}</strong>
          <p>{msg.text}</p>
          <button onClick={() => onDelete(msg.id)}>Delete</button>
        </div>
      ))}
    </div>
  );
});

export function ChatWidget({ roomId, currentUserId, wsUrl }: ChatWidgetProps) {
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputText, setInputText] = useState('');
  const [isConnected, setIsConnected] = useState(false);
  const [typingUsers, setTypingUsers] = useState<string[]>([]);
  const wsRef = useRef<WebSocket | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const ws = new WebSocket(`${wsUrl}/rooms/${roomId}`);
    wsRef.current = ws;

    ws.onopen = () => {
      setIsConnected(true);
    };

    ws.onmessage = (event) => {
      const data = JSON.parse(event.data);
      if (data.type === 'message') {
        setMessages([...messages, data.payload]);
      } else if (data.type === 'typing') {
        setTypingUsers(data.users);
      }
    };

    ws.onclose = () => {
      setIsConnected(false);
    };

    ws.onerror = () => {
      setIsConnected(false);
    };
  }, [roomId, wsUrl]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const sendMessage = async () => {
    if (!inputText.trim() || !wsRef.current) return;

    const message: Message = {
      id: crypto.randomUUID(),
      userId: currentUserId,
      userName: 'Me',
      text: inputText,
      timestamp: Date.now(),
    };

    wsRef.current.send(JSON.stringify({
      type: 'message',
      payload: message,
    }));

    setMessages([...messages, message]);
    setInputText('');
  };

  const handleDelete = (id: string) => {
    setMessages(messages.filter(m => m.id !== id));
    wsRef.current?.send(JSON.stringify({ type: 'delete', id }));
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  };

  return (
    <div className="chat-widget">
      <div className="chat-header">
        <span className={isConnected ? 'status-online' : 'status-offline'}>
          {isConnected ? 'Connected' : 'Disconnected'}
        </span>
      </div>
      <MessageList messages={messages} onDelete={(id) => handleDelete(id)} />
      <div ref={messagesEndRef} />
      {typingUsers.length > 0 && (
        <div className="typing-indicator">
          {typingUsers.join(', ')} {typingUsers.length === 1 ? 'is' : 'are'} typing...
        </div>
      )}
      <div className="chat-input">
        <textarea
          value={inputText}
          onChange={e => setInputText(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder="Type a message..."
          rows={2}
        />
        <button onClick={sendMessage} disabled={!isConnected || !inputText.trim()}>
          Send
        </button>
      </div>
    </div>
  );
}

