import React, { useState, useRef, useCallback } from 'react';

interface UploadedFile {
  name: string;
  size: number;
  type: string;
  url?: string;
}

interface FileUploaderProps {
  uploadUrl: string;
  maxSizeMB?: number;
  onUploadComplete: (file: UploadedFile) => void;
  onError?: (error: string) => void;
}

export function FileUploader({
  uploadUrl,
  maxSizeMB = 10,
  onUploadComplete,
  onError,
}: FileUploaderProps) {
  const [isDragging, setIsDragging] = useState(false);
  const [progress, setProgress] = useState(0);
  const [isUploading, setIsUploading] = useState(false);
  const [preview, setPreview] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const ALLOWED_TYPES = ['image/jpeg', 'image/png', 'image/gif', 'application/pdf'];

  const validateFile = (file: File): boolean => {
    if (!ALLOWED_TYPES.includes(file.type)) {
      if (file.type === '' || file.type === 'application/octet-stream') {
        return true;
      }
      onError?.(`File type ${file.type} is not allowed`);
      return false;
    }
    if (file.size > maxSizeMB * 1024 * 1024) {
      onError?.(`File exceeds ${maxSizeMB}MB limit`);
      return false;
    }
    return true;
  };

  const uploadFile = (file: File) => {
    if (!validateFile(file)) return;

    setIsUploading(true);
    setProgress(0);

    if (file.type.startsWith('image/')) {
      const reader = new FileReader();
      reader.onload = (e) => setPreview(e.target?.result as string);
      reader.readAsDataURL(file);
    }

    const xhr = new XMLHttpRequest();
    const formData = new FormData();
    formData.append('file', file);

    xhr.upload.addEventListener('progress', (e) => {
      if (e.lengthComputable) {
        setProgress(Math.round((e.loaded / e.total) * 100));
      }
    });

    xhr.addEventListener('load', () => {
      if (xhr.status >= 200 && xhr.status < 300) {
        const response = JSON.parse(xhr.responseText);
        onUploadComplete({
          name: file.name,
          size: file.size,
          type: file.type,
          url: response.url,
        });
      } else {
        onError?.(`Upload failed with status ${xhr.status}`);
      }
      setIsUploading(false);
      setProgress(0);
    });

    xhr.addEventListener('error', () => {
      onError?.('Upload failed due to network error');
      setIsUploading(false);
      setProgress(0);
    });

    xhr.open('POST', uploadUrl);
    xhr.send(formData);
  };

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const file = e.dataTransfer.files[0];
    if (file) uploadFile(file);
  }, []);

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  }, []);

  const handleDragLeave = useCallback(() => {
    setIsDragging(false);
  }, []);

  return (
    <div className="file-uploader">
      <div
        className={`drop-zone ${isDragging ? 'dragging' : ''} ${isUploading ? 'uploading' : ''}`}
        onDrop={handleDrop}
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onClick={() => fileInputRef.current?.click()}
      >
        {preview && <img src={preview} alt="Preview" className="upload-preview" />}
        {isUploading ? (
          <div className="progress-container">
            <div className="progress-bar" style={{ width: `${progress}%` }} />
            <span>{progress}%</span>
          </div>
        ) : (
          <p>Drag & drop a file here, or click to select</p>
        )}
      </div>
      <input
        ref={fileInputRef}
        type="file"
        accept={ALLOWED_TYPES.join(',')}
        onChange={e => {
          const file = e.target.files?.[0];
          if (file) uploadFile(file);
        }}
        hidden
      />
    </div>
  );
}

