useEffect(() => {
  let cancelled = false;
  api.get(`/users/${userId}/navigation`)
    .then(data => { if (!cancelled) setNavItems(data); })
    .catch(err => {
      console.error('Failed to load navigation:', err);
      if (!cancelled && err?.response?.status === 401) {
        navigate('/login');
      }
    });
  return () => { cancelled = true; };
}, [userId]);

